# 用 DeepSeek API（最簡單）
from openai import OpenAI  # DeepSeek 兼容 OpenAI 格式

client = OpenAI(
    api_key="your-deepseek-api-key",
    base_url="https://api.deepseek.com"
)

# 數學問題
response = client.chat.completions.create(
    model="deepseek-chat",  # deepseek-chat = DeepSeek V3
    messages=[
        {"role": "user", "content": "解方程：3x² + 7x - 6 = 0"}
    ]
)
print(response.choices[0].message.content)

# DeepSeek-R1（推理模型，類似 o1）
response = client.chat.completions.create(
    model="deepseek-reasoner",  # R1 模型
    messages=[
        {"role": "user", "content": "分析巴以衝突嘅根本原因"}
    ]
)
# R1 會展示思維鏈（Chain of Thought）
